import{c as e,Q as t,j as i,m as o}from"./chunks/framework.BA1dEi98.js";const r="/librislog/next/screenshots/data-import.png",u=JSON.parse('{"title":"Import & Export","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/import-export.md","filePath":"guide/using-librislog/import-export.md","lastUpdated":1780089472000}'),s={name:"guide/using-librislog/import-export.md"};function l(n,a,p,d,h,c){return t(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="import-export" tabindex="-1">Import &amp; Export <a class="header-anchor" href="#import-export" aria-label="Permalink to &quot;Import &amp; Export&quot;">​</a></h1><p>LibrisLog provides multiple ways to get data in and out of the system, ensuring your library is always portable.</p><h2 id="book-import" tabindex="-1">Book Import <a class="header-anchor" href="#book-import" aria-label="Permalink to &quot;Book Import&quot;">​</a></h2><h3 id="search-import" tabindex="-1">Search Import <a class="header-anchor" href="#search-import" aria-label="Permalink to &quot;Search Import&quot;">​</a></h3><p>The most common way to add books is by searching external sources:</p><ol><li>Click &quot;Add Book&quot; in the library</li><li>Enter a title, author, or ISBN in the search box</li><li>The app queries: <ul><li><strong>Open Library</strong> (always, no key required)</li><li><strong>Google Books</strong> (if <code>GOOGLE_BOOKS_API_KEY</code> is set — see <a href="/librislog/next/guide/api-keys.html">API Keys</a>)</li><li><strong>Hardcover.app</strong> (if <code>HARDCOVER_APP_API_TOKEN</code> is set — see <a href="/librislog/next/guide/api-keys.html">API Keys</a>)</li></ul></li><li>Select a result to import with full metadata and cover</li></ol><h3 id="isbn-barcode-scan" tabindex="-1">ISBN Barcode Scan <a class="header-anchor" href="#isbn-barcode-scan" aria-label="Permalink to &quot;ISBN Barcode Scan&quot;">​</a></h3><p>On mobile devices:</p><ol><li>Tap the scan button in the import dialog</li><li>Point the camera at an ISBN barcode</li><li>The app detects the barcode and searches automatically</li></ol><h3 id="manual-entry" tabindex="-1">Manual Entry <a class="header-anchor" href="#manual-entry" aria-label="Permalink to &quot;Manual Entry&quot;">​</a></h3><p>If no search results are found, enter book details manually. All fields are optional except title.</p><h2 id="data-export" tabindex="-1">Data Export <a class="header-anchor" href="#data-export" aria-label="Permalink to &quot;Data Export&quot;">​</a></h2><p>Export your entire library or subsets of data:</p><h3 id="export-formats" tabindex="-1">Export Formats <a class="header-anchor" href="#export-formats" aria-label="Permalink to &quot;Export Formats&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Format</th><th>Description</th></tr></thead><tbody><tr><td><strong>JSON</strong></td><td>Complete data with all metadata and relationships</td></tr><tr><td><strong>CSV</strong></td><td>Tabular format, one row per book</td></tr><tr><td><strong>ZIP</strong></td><td>Combined JSON + cover images</td></tr></tbody></table><h3 id="export-datasets" tabindex="-1">Export Datasets <a class="header-anchor" href="#export-datasets" aria-label="Permalink to &quot;Export Datasets&quot;">​</a></h3><p>Choose which data to include:</p><ul><li>Books (full metadata)</li><li>Reading progress entries</li><li>Tags</li><li>Cover images</li></ul><h3 id="export-process" tabindex="-1">Export Process <a class="header-anchor" href="#export-process" aria-label="Permalink to &quot;Export Process&quot;">​</a></h3><ol><li>Go to the Data page</li><li>Select datasets and format</li><li>Click Export</li><li>Download the generated file</li></ol><h2 id="data-import" tabindex="-1">Data Import <a class="header-anchor" href="#data-import" aria-label="Permalink to &quot;Data Import&quot;">​</a></h2><p>Import data from external sources:</p><p><img src="'+r+`" alt="Data Import" loading="lazy"></p><h3 id="supported-formats" tabindex="-1">Supported Formats <a class="header-anchor" href="#supported-formats" aria-label="Permalink to &quot;Supported Formats&quot;">​</a></h3><ul><li><strong>JSON</strong> — LibrisLog export format</li><li><strong>CSV</strong> — Custom field mapping supported</li></ul><h3 id="field-mapping" tabindex="-1">Field Mapping <a class="header-anchor" href="#field-mapping" aria-label="Permalink to &quot;Field Mapping&quot;">​</a></h3><p>When importing CSV, map source columns to LibrisLog fields:</p><ul><li>Source field dropdown shows all columns from the CSV</li><li>Target field shows available LibrisLog properties</li><li>Optional transform expressions (Python) for data conversion</li></ul><h3 id="transform-dsl" tabindex="-1">Transform DSL <a class="header-anchor" href="#transform-dsl" aria-label="Permalink to &quot;Transform DSL&quot;">​</a></h3><p>Per-field Python expressions allow data transformation:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Examples:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value.upper()              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Convert to uppercase</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">str</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(value))            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Convert to integer then back to string</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://example.com/&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> +</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> value  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Prefix a URL</span></span></code></pre></div><p>Available variables:</p><ul><li><code>value</code> — The field value</li><li><code>row</code> — The entire row as a dictionary</li><li><code>context</code> — Import context (not commonly used)</li></ul><h3 id="predefined-mappings" tabindex="-1">Predefined Mappings <a class="header-anchor" href="#predefined-mappings" aria-label="Permalink to &quot;Predefined Mappings&quot;">​</a></h3><p>Common import formats have predefined mappings:</p><ul><li><strong>Goodreads Export</strong> — Maps Goodreads CSV columns automatically</li></ul><h3 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h3><p>Before importing:</p><ol><li>Parse and preview the data</li><li>Review transformed rows</li><li>Check for errors</li><li>Validate the full dataset</li></ol><p>The import process shows progress with a count of imported and failed rows.</p><h2 id="backup-restore" tabindex="-1">Backup &amp; Restore <a class="header-anchor" href="#backup-restore" aria-label="Permalink to &quot;Backup &amp; Restore&quot;">​</a></h2><p>Backup and restore are admin-only features. See <a href="./administration.html">Administration</a> for details.</p><h2 id="api-access" tabindex="-1">API Access <a class="header-anchor" href="#api-access" aria-label="Permalink to &quot;API Access&quot;">​</a></h2><p>For programmatic import/export, use the REST API. See the <a href="./../../api/">API documentation</a> for details.</p>`,44)])])}const g=e(s,[["render",l]]);export{u as __pageData,g as default};
